const raw = $input.first().json;

// MakeShop 응답 파싱 (배열 or 숫자키 객체)
let orders = [];
if (Array.isArray(raw)) {
  orders = raw;
} else if (raw && typeof raw === 'object') {
  const vals = Object.values(raw);
  if (vals.length > 0 && typeof vals[0] === 'object') {
    orders = vals;
  }
}

if (orders.length === 0) {
  return [];
}

// 오늘 날짜 (KST)
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const today = `${kst.getUTCFullYear()}-${pad(kst.getUTCMonth() + 1)}-${pad(kst.getUTCDate())}`;
const dueAt = `${today}T23:59:59+09:00`;

const items = [];
for (let i = 0; i < orders.length; i++) {
  const o = orders[i];
  const orderNo = String(o.order_cd || o.order_id || o.order_no || `${i}`);
  const pname = o.pname || o.product_name || '상품';
  const qty = parseInt(o.ea || o.quantity || '1', 10);
  const buyer = o.name || o.buyer_name || '';
  const receiver = o.receive_name || buyer;
  const shortName = pname.length > 30 ? pname.substring(0, 30) + '...' : pname;

  items.push({
    json: {
      title: `[출고] ${shortName}${qty > 1 ? ' x' + qty : ''}`,
      sourceChannel: 'makeshop-order',
      sourceMessageId: `${today}:${orderNo}:${i}`,
      sourceText: `MakeShop 출고대기 #${orderNo} ${pname} x${qty} (${buyer})`,
      status: 'todo',
      priority: 'p2',
      category: 'shipment',
      assignee: '이재혁',
      dueAt: dueAt,
      relatedProject: '출고',
      detailsMerge: {
        orderNumber: orderNo,
        items: [{ name: pname, qty: qty }],
        buyer: buyer,
        receiver: receiver
      }
    }
  });
}

return items;
